import { useEffect, useState } from "react";
import api from "../api";

/** ========= Config ========= **/
const PAGE_SIZE = 10;
const ROLES = ["ADMIN", "SALES", "ACCOUNTANT"];
const STATUSES = ["ACTIVE", "INACTIVE"];

/** Chuẩn hoá Page<?> từ BE */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return {
        list: d?.content || [],
        pages: typeof d?.totalPages === "number" ? d.totalPages : 1,
    };
}

/** debounce nhỏ cho ô tìm kiếm */
function useDebounce(value, delay = 450) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

function emptyForm() {
    return {
        username: "",
        fullName: "",
        email: "",
        phone: "",
        role: "SALES",
        status: "ACTIVE", // ACTIVE/INACTIVE
        password: "",
        confirm: "",
        resetPassword: false,
    };
}

export default function Users() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q);
    const [role, setRole] = useState("");
    const [status, setStatus] = useState("");

    // modal
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState(emptyForm());

    useEffect(() => {
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page, dq, role, status]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/users", {
                params: {
                    q: dq || undefined,
                    role: role || undefined,
                    status: status || undefined,
                    page,
                    size: PAGE_SIZE,
                    sort: "id,desc",
                },
            });
            const { list, pages } = normalizePage(data);
            setRows(
                list.map((u) => ({
                    id: u.id,
                    username: u.username,
                    fullName: u.fullName || u.name,
                    email: u.email,
                    phone: u.phone,
                    role: (u.role || u.roleName || u.roles?.[0] || "")
                        .toString()
                        .replace(/^ROLE_/, "") || "SALES",
                    status: u.active === false ? "INACTIVE" : "ACTIVE",
                    active: u.active !== false,
                }))
            );
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm(emptyForm());
        setShow(true);
    }
    function openEdit(row) {
        setEditing(row);
        setForm({
            username: row.username || "",
            fullName: row.fullName || "",
            email: row.email || "",
            phone: row.phone || "",
            role: row.role || "SALES",
            status: row.status || "ACTIVE",
            password: "",
            confirm: "",
            resetPassword: false,
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();

        try {
            if (!editing) {
                // ====== CREATE ======
                if (!form.password?.trim()) {
                    alert("Mật khẩu không được để trống");
                    return;
                }
                if (form.password !== form.confirm) {
                    alert("Xác nhận mật khẩu không khớp");
                    return;
                }

                const payload = {
                    username: form.username?.trim(),
                    fullName: form.fullName?.trim(),
                    email: form.email?.trim(),
                    phone: form.phone?.trim(),
                    password: form.password,
                    roleName: form.role,
                    active: form.status === "ACTIVE",
                };

                await api.post("/api/users", payload);
            } else {
                // ====== UPDATE ======
                const payload = {
                    fullName: form.fullName?.trim(),
                    email: form.email?.trim(),
                    phone: form.phone?.trim(),
                    roleName: form.role,
                    active: form.status === "ACTIVE",
                };
                if (form.resetPassword) {
                    if (!form.password?.trim()) {
                        alert("Nhập mật khẩu mới");
                        return;
                    }
                    if (form.password !== form.confirm) {
                        alert("Xác nhận mật khẩu không khớp");
                        return;
                    }
                    payload.password = form.password;
                }
                await api.put(`/api/users/${editing.id}`, payload);
            }

            setShow(false);
            if (rows.length === 0 && page > 0) setPage((p) => p - 1);
            await load();
            alert(editing ? "Đã cập nhật người dùng" : "Đã tạo người dùng");
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                (typeof err?.response?.data === "object"
                    ? Object.values(err.response.data).join("; ")
                    : "") ||
                "Lưu người dùng thất bại";
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá người dùng ${row.username}?`)) return;
        try {
            await api.delete(`/api/users/${row.id}`);
            if (rows.length === 1 && page > 0) setPage((p) => p - 1);
            else await load();
            alert("Đã xoá");
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Xoá người dùng thất bại";
            alert(msg);
        }
    }

    return (
        <div className="space-y-4">
            {/* Toolbar đồng bộ */}
            <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-3 mb-2">
                <div>
                    <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                    <p className="text-sm text-slate-500">Quản trị viên có thể quản lý người dùng</p>
                </div>

                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="w-80 px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            placeholder="Tên đăng nhập / Họ tên / Email / SĐT…"
                            value={q}
                            onChange={(e) => {
                                setQ(e.target.value);
                                setPage(0);
                            }}
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Vai trò</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={role}
                            onChange={(e) => {
                                setRole(e.target.value);
                                setPage(0);
                            }}
                        >
                            <option value="">Tất cả</option>
                            {ROLES.map((r) => (
                                <option key={r} value={r}>
                                    {r}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={status}
                            onChange={(e) => {
                                setStatus(e.target.value);
                                setPage(0);
                            }}
                        >
                            <option value="">Tất cả</option>
                            {STATUSES.map((s) => (
                                <option key={s} value={s}>
                                    {s}
                                </option>
                            ))}
                        </select>
                    </div>

                    <button
                        onClick={openCreate}
                        className="ml-auto px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                    >
                        Thêm người dùng
                    </button>
                </div>
            </div>

            {/* Bảng */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên đăng nhập</th>
                            <th className="px-4 py-3 text-left">Họ tên</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Vai trò</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((u) => (
                                <tr key={u.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{u.username}</td>
                                    <td className="px-4 py-3">{u.fullName || "-"}</td>
                                    <td className="px-4 py-3">{u.email || "-"}</td>
                                    <td className="px-4 py-3">{u.phone || "-"}</td>
                                    <td className="px-4 py-3">{u.role}</td>
                                    <td className="px-4 py-3">
                      <span
                          className={
                              "px-2 py-0.5 rounded-full text-xs " +
                              (u.status === "ACTIVE"
                                  ? "bg-emerald-100 text-emerald-700"
                                  : "bg-slate-100 text-slate-700")
                          }
                      >
                        {u.status}
                      </span>
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button
                                                onClick={() => openEdit(u)}
                                                className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                            >
                                                Sửa
                                            </button>
                                            <button
                                                onClick={() => remove(u)}
                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                            >
                                                Xóa
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{totalPages}</div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">
                                {editing ? "Sửa người dùng" : "Thêm người dùng"}
                            </div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShow(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Tên đăng nhập</label>
                                <input
                                    required
                                    disabled={!!editing}
                                    value={form.username}
                                    onChange={(e) => setForm((f) => ({ ...f, username: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Họ tên</label>
                                <input
                                    required
                                    value={form.fullName}
                                    onChange={(e) => setForm((f) => ({ ...f, fullName: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input
                                    required
                                    type="email"
                                    value={form.email}
                                    onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input
                                    value={form.phone}
                                    onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Vai trò</label>
                                <select
                                    value={form.role}
                                    onChange={(e) => setForm((f) => ({ ...f, role: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {ROLES.map((r) => (
                                        <option key={r} value={r}>
                                            {r}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select
                                    value={form.status}
                                    onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {STATUSES.map((s) => (
                                        <option key={s} value={s}>
                                            {s}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Mật khẩu */}
                            {!editing ? (
                                <>
                                    <div>
                                        <label className="text-sm text-slate-600">Mật khẩu</label>
                                        <input
                                            type="password"
                                            value={form.password}
                                            onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                                            className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                            required
                                        />
                                    </div>
                                    <div>
                                        <label className="text-sm text-slate-600">Xác nhận mật khẩu</label>
                                        <input
                                            type="password"
                                            value={form.confirm}
                                            onChange={(e) => setForm((f) => ({ ...f, confirm: e.target.value }))}
                                            className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                            required
                                        />
                                    </div>
                                </>
                            ) : (
                                <>
                                    <div className="md:col-span-2 flex items-center gap-2">
                                        <input
                                            id="resetPw"
                                            type="checkbox"
                                            checked={form.resetPassword}
                                            onChange={(e) =>
                                                setForm((f) => ({ ...f, resetPassword: e.target.checked }))
                                            }
                                        />
                                        <label htmlFor="resetPw" className="text-sm text-slate-600 select-none">
                                            Đặt mật khẩu mới
                                        </label>
                                    </div>
                                    {form.resetPassword && (
                                        <>
                                            <div>
                                                <label className="text-sm text-slate-600">Mật khẩu mới</label>
                                                <input
                                                    type="password"
                                                    value={form.password}
                                                    onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                                    required
                                                />
                                            </div>
                                            <div>
                                                <label className="text-sm text-slate-600">Xác nhận mật khẩu</label>
                                                <input
                                                    type="password"
                                                    value={form.confirm}
                                                    onChange={(e) => setForm((f) => ({ ...f, confirm: e.target.value }))}
                                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                                    required
                                                />
                                            </div>
                                        </>
                                    )}
                                </>
                            )}

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Huỷ
                                </button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
